using System;
using System.Reflection;
using System.Linq;

var dll = Assembly.LoadFrom("/home/runner/.nuget/packages/modelcontextprotocol/1.2.0/lib/net9.0/ModelContextProtocol.dll");

// Find all attributes
var attributes = dll.GetTypes()
    .Where(t => t.Name.Contains("McpServer") && (t.Name.Contains("Attribute") || t.Name.Contains("Tool") || t.Name.Contains("Prompt")))
    .OrderBy(t => t.Name)
    .ToList();

Console.WriteLine("=== Found Types with 'McpServer', 'Tool', or 'Prompt' in name ===\n");
foreach (var attr in attributes)
{
    Console.WriteLine($"Type: {attr.FullName}");
    Console.WriteLine($"  BaseType: {attr.BaseType?.FullName}");

    if (attr.Name.EndsWith("Attribute"))
    {
        var ctors = attr.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
        Console.WriteLine($"  Constructors:");
        foreach (var ctor in ctors)
        {
            var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            Console.WriteLine($"    {attr.Name}({@params})");
        }
    }
    Console.WriteLine();
}

// Find extension methods
Console.WriteLine("\n=== Extension Methods in Microsoft.Extensions.DependencyInjection ===\n");
var extensionTypes = dll.GetTypes()
    .Where(t => t.Namespace == "Microsoft.Extensions.DependencyInjection")
    .ToList();

foreach (var extType in extensionTypes)
{
    Console.WriteLine($"\nNamespace: {extType.Namespace}");
    Console.WriteLine($"Type: {extType.Name}");

    var methods = extType.GetMethods(BindingFlags.Public | BindingFlags.Static)
        .Where(m => m.Name.Contains("AddMcp") || m.Name.Contains("With") || m.Name.Contains("Stdio"))
        .OrderBy(m => m.Name)
        .ToList();

    if (methods.Any())
    {
        Console.WriteLine($"  Methods:");
        foreach (var method in methods)
        {
            var @params = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
            var returnType = method.ReturnType.Name;
            Console.WriteLine($"    {returnType} {method.Name}({@params})");
        }
    }
}
EOF
