using Microsoft.Extensions.DependencyInjection;

// Find attributes
var types = typeof(McpServerToolAttribute).Assembly.GetTypes();

Console.WriteLine("=== Attribute Types ===\n");
var attrTypes = types.Where(t => t.Name.Contains("McpServer") && (t.Name.EndsWith("Attribute"))).ToList();
foreach (var attr in attrTypes.OrderBy(t => t.Name))
{
    Console.WriteLine($"{attr.FullName}");
    var ctors = attr.GetConstructors(BindingFlags.Public | BindingFlags.Instance);
    foreach (var ctor in ctors)
    {
        var @params = string.Join(", ", ctor.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
        Console.WriteLine($"  Constructor: {attr.Name}({@params})");
    }
    Console.WriteLine();
}

