var extensionMethods = types
    .Where(t => t.Namespace == "Microsoft.Extensions.DependencyInjection" && t.Name.Contains("Extensions"))
    .SelectMany(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static))
    .Where(m => m.Name.StartsWith("With") || m.Name.StartsWith("Add"))
    .OrderBy(m => m.Name)
    .ToList();

